SELECT dhb_name, population
FROM district_health_boards
ORDER BY population DESC;

SELECT dhb_name, population
FROM district_health_boards
ORDER BY population DESC;

SELECT SUM(fully_vaccinated) AS total_fully_vaccinated
FROM vaccination_stats
WHERE dhb = '1';

SELECT population
FROM district_health_boards
WHERE dhb_id = 1;

SELECT dhb, SUM(fully_vaccinated) AS total_fully_vaccinated
FROM vaccination_stats
GROUP BY dhb;
